SELECT * FROM novel_tag
WHERE novel_id IN

    #{id}

SELECT DISTINCT nt.tag_name
FROM user_behavior_log ubl
         JOIN novel_tag nt ON ubl.novel_id = nt.novel_id
WHERE ubl.user_id = #{userId}
ORDER BY ubl.created_at DESC
    LIMIT #{limit}

SELECT DISTINCT n.*, COUNT(DISTINCT nt.tag_name) as match_count
FROM novel n
JOIN novel_tag nt ON n.id = nt.novel_id
WHERE 1=1

    AND nt.tag_name IN

        #{tag}



    AND n.id NOT IN (
    SELECT novel_id FROM bookshelf WHERE user_id = #{userId}
    UNION
    SELECT novel_id FROM user_behavior_log WHERE user_id = #{userId}
    )

GROUP BY n.id
ORDER BY (COUNT(DISTINCT nt.tag_name) * RAND()) DESC
LIMIT #{limit}
